// Parse scraped elements into structured price data
const items = $input.all();
const results = [];

for (const item of items) {
  const scraped = item.json;
  const prices = scraped?.data?.[0]?.results || [];
  const titles = scraped?.data?.[1]?.results || [];

  for (let i = 0; i < Math.min(prices.length, titles.length); i++) {
    const rawPrice = prices[i]?.text?.replace(/[^0-9.]/g, '') || '0';
    const price = parseFloat(rawPrice);
    const name  = titles[i]?.text?.trim() || 'Unknown Product';

    if (price > 0) {
      results.push({
        productName: name,
        competitorPrice: price,
        competitorUrl: item.json.url || '',
        scrapedAt: new Date().toISOString(),
      });
    }
  }
}

return results.map(r => ({ json: r }));

// Filter for significant price gaps (> 10% cheaper at competitor)
const comparisons = $input.all();
const flags = [];

for (const item of comparisons) {
  const d = item.json;
  if (!d.ourPrice || !d.competitorPrice) continue;

  const diff = ((d.ourPrice - d.competitorPrice) / d.ourPrice) * 100;

  if (diff > 10) {
    flags.push({
      product: d.productName,
      ourPrice: d.ourPrice,
      competitorPrice: d.competitorPrice,
      diffPct: diff.toFixed(1),
      competitorUrl: d.competitorUrl,
      status: 'TOO_EXPENSIVE',
    });
  } else if (diff < -15) {
    flags.push({
      product: d.productName,
      ourPrice: d.ourPrice,
      competitorPrice: d.competitorPrice,
      diffPct: diff.toFixed(1),
      competitorUrl: d.competitorUrl,
      status: 'UNDERPRICED',
    });
  }
}

// Pass total count so next node can decide whether to send alert
return [{ json: { flags, count: flags.length } }];
